try {
  const rawResponse = $input.item.json.content[0].text;
  const extractedData = JSON.parse(rawResponse);
  return { json: extractedData };
} catch (e) {
  throw new Error('Failed to parse AI response: ' + e.message);
}

const data = $input.item.json.body;
const month = new Date().getMonth() + 1;
const bookingType = (month >= 3 && month <= 8) ? "Office" : "Virtual";
const bookingLink = (bookingType === "Office") 
  ? "https://calendly.com/swans-santiago-p/summer-spring" 
  : "https://calendly.com/swans-santiago-p/winter-autumn";

data.bookingType = bookingType;
data.bookingLink = bookingLink;
return { json: data };
